const body = $input.first().json.body || $input.first().json;
const event = body;
const dispute = event?.data?.object || {};

const disputeId = dispute.id || '';
const chargeId = dispute.charge || '';
const customerId = dispute.payment_intent || '';
const disputeAmount = dispute.amount || 0;
const currency = (dispute.currency || 'usd').toUpperCase();
const disputeAmountDisplay = `$${(disputeAmount / 100).toFixed(2)} ${currency}`;
const reason = dispute.reason || 'unknown';
const status = dispute.status || 'needs_response';

const reasonLabels = {
  bank_cannot_process: 'Bank Cannot Process',
  check_returned: 'Check Returned',
  credit_not_processed: 'Credit Not Processed',
  customer_initiated: 'Customer Initiated',
  debit_not_authorized: 'Debit Not Authorized',
  duplicate: 'Duplicate Charge',
  fraudulent: 'Fraudulent',
  general: 'General',
  incorrect_account_details: 'Incorrect Account Details',
  insufficient_funds: 'Insufficient Funds',
  product_not_received: 'Product Not Received',
  product_unacceptable: 'Product Unacceptable',
  subscription_canceled: 'Subscription Cancelled',
  unrecognized: 'Unrecognized'
};

const reasonDisplay = reasonLabels[reason] || reason;
const stripeDisputeUrl = `https://dashboard.stripe.com/disputes/${disputeId}`;

// Due by date
const evidenceDueBy = dispute.evidence_details?.due_by
  ? new Date(dispute.evidence_details.due_by * 1000).toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' })
  : 'Check Stripe dashboard';

return [{ json: {
  disputeId,
  chargeId,
  customerId,
  disputeAmount,
  disputeAmountDisplay,
  currency,
  reason,
  reasonDisplay,
  status,
  stripeDisputeUrl,
  evidenceDueBy,
  createdAt: new Date().toISOString(),
  rawPayload: JSON.stringify(body)
} }];

const users = $input.first().json;
const user = Array.isArray(users) ? users[0] : users;
const parsed = $('Parse Dispute Payload').first().json;

return [{ json: {
  ...parsed,
  userId: user?.id || '',
  email: user?.email || 'unknown@unknown.com',
  firstName: user?.first_name || 'Unknown',
  planTier: user?.plan_tier || 'unknown'
} }];

